SELECT c.commentid AS commentId, c.boardid AS boardId, CASE WHEN u.joined = 'N' THEN '탈퇴한 회원' ELSE c.userid END AS userId, CASE WHEN u.joined = 'N' THEN '탈퇴한 회원' ELSE c.username END AS userName, c.content, c.parentid AS parentId, c.hidden, c.createdat AS createdAt, c.updatedat AS updatedAt FROM freeboard_comment c LEFT JOIN users u ON c.userid = u.id WHERE c.boardid = #{boardId}
AND c.hidden = 0
ORDER BY c.createdat ASC

