UPDATE freeboard_comment
SET hidden = #{hidden}
WHERE commentid = #{commentId}

UPDATE freeboard
SET commentcount = commentcount + 1
WHERE boardid = #{boardId}

UPDATE freeboard
SET commentcount = GREATEST(commentcount - 1, 0)
WHERE boardid = #{boardId}

UPDATE freeboard
SET commentcount = GREATEST(commentcount - #{count}, 0)
WHERE boardid = #{boardId}
